## 3. APP.tsx NAVIGATION WIRING

How views are pushed onto the stack:

```typescript
type NavViewData =
  | { type: 'grid' }
  | { type: 'clipboard' }
  | { type: 'snippets' }
  | { type: 'emoji' }
  | { type: 'file-search' }
  | { type: 'detail'; item: ListItemData };

// In App.tsx root search handler:
const handleDrillIn = useCallback(() => {
  const item = allItems[selectedIndex];
  if (!item) return;

  if (item.id === 'clipboard-history') {
    push('Clipboard History', { type: 'clipboard' });
  } else if (item.id === 'snippets') {
    push('Snippets', { type: 'snippets' });
  }
  // ... etc
}, [push, allItems, selectedIndex]);

// In render:
function renderCurrentView() {
  const entry = nav.currentEntry;
  if (!entry) return null;

  switch (entry.data.type) {
    case 'clipboard':
      return <ClipboardHistoryView />;
    case 'snippets':
      return <SnippetManagerView />;
    // ... etc
  }
}

const isFullView =
  viewType === 'clipboard' ||
  viewType === 'snippets' ||
  viewType === 'emoji' ||
  viewType === 'file-search';

// Full-screen views hide SearchBar from root:
return (
  <CommandPalette isLoading>
    {!isFullView && <SearchBar ... />}
    {isFullView && nav.currentEntry ? (
      <div className={`command-palette__nav-view${navDirectionClass}`}>
        {renderCurrentView()}
      </div>
    ) : (
      // Root view with List/Detail
    )}
    {!isFullView && <ActionPanel ... />}
  </CommandPalette>
);
```

