## 4. TYPES.ts - CORE DATA INTERFACES

```typescript
export interface ListItemData {
  id: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
  accessories?: ListItemAccessoryData[];
  detail?: ListItemDetailData;
}

export interface ListItemAccessoryData {
  text?: string;
  icon?: ReactNode;
  date?: Date;
  tag?: {
    text: string;
    color?: TagColor;  // 'blue' | 'green' | 'orange' | 'red' | 'purple' | 'yellow'
  };
  tooltip?: string;
}

export interface ListItemDetailData {
  markdown: string;
  metadata?: ListItemMetadataEntry[];
}

export type ListItemMetadataEntry =
  | { type: 'label'; title: string; text?: string }
  | { type: 'link'; title: string; text: string; target: string }
  | { type: 'tag-list'; title: string; tags: { text: string; color?: TagColor }[] }
  | { type: 'separator' };

export interface SectionData {
  title: string;
  items: ListItemData[];
}

export interface GridItemData {
  id: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
}

export type ColorCategory = 'warm' | 'cool' | 'neutral';

export interface ColorItemData extends GridItemData {
  color: string;
  category: ColorCategory;
}
