### Example Form Usage (from SnippetManagerView):
```typescript
function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
  const [form, setForm] = useState<SnippetFormState>({
    name: snippet?.name ?? '',
    keyword: snippet?.keyword ?? '',
    snippet: snippet?.content ?? '',
    category: snippet?.category ?? 'general',
    tags: snippet?.tags.map(t => t.text.toLowerCase()) ?? [],
  });
  const [errors, setErrors] = useState<Partial<Record<keyof SnippetFormState, string>>>({});

  const handleSubmit = useCallback(() => {
    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
    if (!form.name.trim()) newErrors.name = 'Name is required';
    if (!form.snippet.trim()) newErrors.snippet = 'Snippet content is required';
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;
    onSubmit(form);
  }, [form, onSubmit]);

  useKeyboardShortcut({ key: 'Enter', meta: true }, handleSubmit);

  return (
    <Form onSubmit={handleSubmit}>
      <FormTextField
        label="Name"
        value={form.name}
        onChange={v => setForm(prev => ({ ...prev, name: v }))}
        placeholder="e.g. Email Signature"
        error={errors.name}
        autoFocus
      />
      <FormTextField
        label="Keyword"
        value={form.keyword}
        onChange={v => setForm(prev => ({ ...prev, keyword: v }))}
        placeholder="e.g. !sig"
        description="Type this to expand the snippet"
      />
      <FormDropdown
        label="Category"
        value={form.category}
        onChange={v => setForm(prev => ({ ...prev, category: v }))}
        options={FORM_CATEGORY_OPTIONS}
        placeholder="Select a category"
      />
      <FormTagPicker
        label="Tags"
        value={form.tags}
        onChange={v => setForm(prev => ({ ...prev, tags: v }))}
        options={FORM_TAG_OPTIONS}
        placeholder="Add tags..."
        description="Categorize your snippet with tags"
      />
      <FormTextArea
        label="Snippet"
        value={form.snippet}
        onChange={v => setForm(prev => ({ ...prev, snippet: v }))}
        placeholder="Enter your snippet content..."
        error={errors.snippet}
        rows={5}
      />
    </Form>
  );
}
```

