## 7. HOOKS & PATTERNS

### useNavigation() Hook
```typescript
const nav = useNavigation();
// Returns:
// - nav.push(title, data): Push view onto stack
// - nav.pop(): Pop current view
// - nav.popToRoot(): Clear stack to root
// - nav.currentEntry: Current NavViewData or null (null = root)
// - nav.breadcrumbs: Array<{ label, onBack? }>
// - nav.canGoBack: boolean
// - nav.direction: 'push' | 'pop' | 'none'
// - nav.stackDepth: number
// - nav.navKey: number (for animation keys)
```

### useToast() Hook
```typescript
const { toasts, show: showToast, hide: hideToast } = useToast();
showToast({ style: 'success' | 'error' | 'info', title: string, message?: string });
// Auto-dismisses after 3s
```

### useHUD() Hook
```typescript
const { items: hudItems, show: showHUD } = useHUD();
showHUD({ icon: ReactNode, title: string });
// Floating pill at bottom-center, auto-dismisses after 1.5s
```

### useAlert() Hook
```typescript
const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
confirmAlert({
  title: string,
  message: string,
  icon?: ReactNode,
  primaryAction: { label: string, style: 'default' | 'destructive' | 'cancel', onAction: () => void },
  dismissAction?: { label: string, style: 'cancel', onAction: () => void },
});
```

### useKeyboardShortcut() Hook
```typescript
useKeyboardShortcut(
  { key: string, meta?: boolean, ctrl?: boolean, alt?: boolean, shift?: boolean },
  handler: (e: KeyboardEvent) => void,
  options?: { enabled?: boolean, preventDefault?: boolean }
);
// Examples:
// { key: 'k', meta: true }  => ⌘K
// { key: 'Enter', meta: true } => ⌘Enter
// { key: 'p', ctrl: true } => Ctrl+P (Emacs navigation)
```

