#### **Pattern: ClipboardHistoryView** (`src/components/clipboard_history/clipboard_history_view.tsx`)
This is the **primary pattern** for full-screen views. Structure:

```typescript
export function ClipboardHistoryView() {
  // 1. LOCAL STATE
  const nav = useNavigation();  // For breadcrumbs
  const [entries, setEntries] = useState<ClipboardEntry[]>(MOCK_DATA);
  const [query, setQuery] = useState('');
  const [filterValue, setFilterValue] = useState('all');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const { items: hudItems, show: showHUD } = useHUD();
  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();

  // 2. DERIVED STATE (useMemo for efficiency)
  const filtered = useMemo(() => { ... }, [entries, query, filterValue]);

  // 3. CALLBACKS
  const handleQueryChange = useCallback((value: string) => { ... }, []);
  const handleFilterChange = useCallback((value: string) => { ... }, []);
  const handleActiveIndexChange = useCallback((index: number) => { ... }, []);
  const handleCopy = useCallback(() => { showHUD(...) }, [showHUD]);
  const handleDelete = useCallback(() => { confirmAlert(...) }, [confirmAlert, showHUD]);

  // 4. KEYBOARD SHORTCUTS
  useKeyboardShortcut({ key: 'k', meta: true }, toggleActions);
  useKeyboardShortcut({ key: 'c', meta: true }, handleCopy);
  useKeyboardShortcut({ key: 'Backspace', meta: true }, handleDelete);

  // 5. ACTION DROPDOWN SECTIONS
  const dropdownSections: DropdownSection[] = useMemo(() => [
    {
      title: 'Actions',
      actions: [
        { label: 'Copy', shortcut: <Kbd keys={['⌘', 'C']} />, onClick: handleCopy },
      ],
    },
    {
      title: 'Danger Zone',
      actions: [
        { label: 'Delete', shortcut: <Kbd keys={['⌘', '⌫']} />, onClick: handleDelete },
      ],
    },
  ], [handleCopy, handleDelete]);

  // 6. FULL-SCREEN LAYOUT (always this structure)
  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search Clipboard..."
        activeDescendantId={activeDescendantId}
        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
        dropdown={
          <SearchDropdown
            sections={FILTER_SECTIONS}
            value={filterValue}
            onChange={handleFilterChange}
          />
        }
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          {totalItemCount === 0 ? (
            <EmptyState icon={...} title="No Results" description="..." />
          ) : (
            <List
              itemCount={totalItemCount}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleAction}
            >
              {/* Render ListSection + ListItem children */}
            </List>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Clipboard History"
        actions={[
          { label: 'Paste', shortcut: <Kbd keys={['↵']} /> },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      {alertState && <Alert {...alertState} onDismiss={dismissAlert} />}
      <HUDContainer items={hudItems} />
    </>
  );
}
```

#### **Pattern: SnippetManagerView** (`src/components/snippet_manager/snippet_manager_view.tsx`)
Advanced example with **sub-views** (list + form editing):

```typescript
type SnippetSubView = 'list' | 'create' | 'edit';

export function SnippetManagerView() {
  const nav = useNavigation();
  const [subView, setSubView] = useState<SnippetSubView>('list');
  const [editingSnippet, setEditingSnippet] = useState<SnippetEntry | undefined>();

  // ... same patterns as ClipboardHistoryView

  const handleFormSubmit = useCallback((form: SnippetFormState) => {
    if (subView === 'edit' && editingSnippet) {
      // Update existing entry
      setEntries(prev => prev.map(e => 
        e.id === editingSnippet.id ? { ...e, ...form } : e
      ));
      showHUD({ title: 'Snippet Updated' });
    } else {
      // Create new entry
      setEntries(prev => [newEntry, ...prev]);
      showHUD({ title: 'Snippet Created' });
    }
    setSubView('list');
  }, [subView, editingSnippet, showHUD]);

  // Conditional sub-view rendering
  if (subView !== 'list') {
    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
    return (
      <>
        <SearchBar value="" onChange={() => {}} placeholder={formTitle} 
          breadcrumbs={[...nav.breadcrumbs, { label: 'Snippets' }]} />
        <div className="command-palette__body">
          <div className="command-palette__list-container">
            <EditSnippetView snippet={editingSnippet} onSubmit={handleFormSubmit} />
          </div>
        </div>
        <ActionPanel contextLabel={formTitle} ... />
        <HUDContainer items={hudItems} />
      </>
    );
  }

  // List view (same pattern as ClipboardHistoryView)
  return (
    <>
      {/* SearchBar, List, ActionPanel, HUDContainer */}
    </>
  );
}
```

