```typescript
const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
confirmAlert({
  title: string,
  message: string,
  icon?: ReactNode,
  primaryAction: { label: string, style: 'default' | 'destructive' | 'cancel', onAction: () => void },
  dismissAction?: { label: string, style: 'cancel', onAction: () => void },
});
```

