@use '../../styles/tokens' as *;

.settings-view {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow: hidden;
}

.settings-section {
  padding: $space-3 $space-4 $space-1;

  &__title {
    font-size: $font-xs;
    font-weight: $font-weight-medium;
    color: $text-600;
    letter-spacing: 0.1px;
    margin-bottom: $space-2;
  }
}

.settings-extension {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-surface-hover;
  }

  &__icon {
    flex-shrink: 0;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;

    svg {
      width: 28px;
      height: 28px;
    }
  }

  &__info {
    flex: 1;
    min-width: 0;
  }

  &__name {
    font-size: $font-base;
    color: $color-text-primary;
    font-weight: $font-weight-medium;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__meta {
    font-size: $font-xs;
    color: $text-400;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__toggle {
    flex-shrink: 0;
  }
}

$toggle-width: 36px;
$toggle-height: 20px;
$toggle-knob-size: 16px;
$toggle-padding: 2px;

.settings-toggle {
  position: relative;
  display: inline-flex;
  align-items: center;
  cursor: pointer;
}

.settings-toggle__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  pointer-events: none;

  &:focus-visible + .settings-toggle__track {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }
}

.settings-toggle__track {
  width: $toggle-width;
  height: $toggle-height;
  border-radius: $radius-pill;
  background: $text-100;
  transition: background-color $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked + & {
    background: $color-accent;
  }
}

.settings-toggle__knob {
  position: absolute;
  top: $toggle-padding;
  left: $toggle-padding;
  width: $toggle-knob-size;
  height: $toggle-knob-size;
  border-radius: 50%;
  background: white;
  transition: transform $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked ~ & {
    transform: translateX(#{$toggle-width - $toggle-knob-size - $toggle-padding * 2});
  }
}

.settings-hotkey {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-2 0;

  &__label {
    font-size: $font-sm;
    color: $text-600;
    font-weight: $font-weight-semibold;
    flex: 1;
  }
}

.settings-action-row {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-surface-hover;
  }

  &__icon {
    flex-shrink: 0;
    width: 20px;
    height: 20px;
    color: $text-600;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  &__label {
    font-size: $font-base;
    color: $color-text-primary;
    flex: 1;
  }

  &__hint {
    font-size: $font-xs;
    color: $text-400;
  }

  &--destructive &__label {
    color: $color-destructive;
  }

  &--destructive &__icon {
    color: $color-destructive;
  }
}

import { useCallback, useMemo, useState } from 'react';
import {
  type ExtensionEntry,
  MOCK_EXTENSIONS,
} from '../../data/settings_data';
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
import { useNavigation } from '../../hooks/use_navigation';
import { ActionPanel } from '../action_panel/action_panel';
import type { DropdownSection } from '../action_panel/actions_dropdown';
import { Alert } from '../alert/alert';
import { FormCheckbox } from '../form/form_checkbox';
import { FormDropdown } from '../form/form_dropdown';
import { FormSeparator } from '../form/form_separator';
import { HUDContainer } from '../hud/hud_container';
import { Kbd } from '../kbd/kbd';
import { SearchBar } from '../search_bar/search_bar';
import type { SearchDropdownSection } from '../search_bar/search_dropdown';
import { SearchDropdown } from '../search_bar/search_dropdown';
import './settings_view.scss';

type SettingsTab = 'general' | 'extensions' | 'advanced';

interface GeneralSettings {
  appearance: string;
  windowWidth: string;
  showRecentApps: boolean;
  showDock: boolean;
  fontSize: string;
}

const TAB_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      { label: 'General', value: 'general' },
      { label: 'Extensions', value: 'extensions' },
      { label: 'Advanced', value: 'advanced' },
    ],
  },
];

const APPEARANCE_OPTIONS = [
  { label: 'Dark', value: 'dark' },
  { label: 'Light', value: 'light' },
  { label: 'System', value: 'system' },
];

const WINDOW_WIDTH_OPTIONS = [
  { label: 'Small (680px)', value: 'small' },
  { label: 'Medium (750px)', value: 'medium' },
  { label: 'Large (820px)', value: 'large' },
];

const FONT_SIZE_OPTIONS = [
  { label: 'Small', value: 'small' },
  { label: 'Default', value: 'default' },
  { label: 'Large', value: 'large' },
];

function ToggleSwitch({
  checked,
  onChange,
  label,
}: {
  checked: boolean;
  onChange: (checked: boolean) => void;
  label: string;
}) {
  return (
    <label className="settings-toggle">
      <input
        type="checkbox"
        className="settings-toggle__input"
        checked={checked}
        onChange={e => onChange(e.target.checked)}
        aria-label={label}
      />
      <div className="settings-toggle__track" />
      <div className="settings-toggle__knob" />
    </label>
  );
}

function SuccessHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M3.5 8.5L6.5 11.5L12.5 4.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ExportIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M8 2v8M4.5 6L8 2l3.5 4"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M3 11v2.5h10V11"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ImportIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M8 10V2M4.5 6L8 10l3.5-4"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M3 11v2.5h10V11"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function TrashIconSmall() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M12 5v8.5a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1V5M3 5h10M6.5 5V3.5a1 1 0 0 1 1-1h1a1 1 0 0 1 1 1V5"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function RefreshIconSmall() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M13 8A5 5 0 1 1 8 3h3"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M11 1l2 2-2 2"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function GeneralTab({
  settings,
  onSettingsChange,
}: {
  settings: GeneralSettings;
  onSettingsChange: (settings: GeneralSettings) => void;
}) {
  return (
    <div className="form">
      <div className="form__fields">
        <FormDropdown
          label="Appearance"
          value={settings.appearance}
          onChange={v => onSettingsChange({ ...settings, appearance: v })}
          options={APPEARANCE_OPTIONS}
        />
        <FormDropdown
          label="Window Width"
          value={settings.windowWidth}
          onChange={v => onSettingsChange({ ...settings, windowWidth: v })}
          options={WINDOW_WIDTH_OPTIONS}
        />
        <FormDropdown
          label="Font Size"
          value={settings.fontSize}
          onChange={v => onSettingsChange({ ...settings, fontSize: v })}
          options={FONT_SIZE_OPTIONS}
        />
        <FormSeparator />
        <FormCheckbox
          label="Show Recent Applications"
          checked={settings.showRecentApps}
          onChange={v => onSettingsChange({ ...settings, showRecentApps: v })}
          description="Display recently used apps in the root search"
        />
        <FormCheckbox
          label="Show Dock Apps"
          checked={settings.showDock}
          onChange={v => onSettingsChange({ ...settings, showDock: v })}
          description="Include Dock applications in search results"
        />
        <FormSeparator />
        <div className="settings-hotkey">
          <span className="settings-hotkey__label">Raycast Hotkey</span>
          <Kbd keys={['⌥', 'Space']} />
        </div>
      </div>
    </div>
  );
}

function ExtensionsTab({
  extensions,
  onToggle,
  query,
}: {
  extensions: ExtensionEntry[];
  onToggle: (id: string) => void;
  query: string;
}) {
  const filtered = useMemo(() => {
    if (!query) return extensions;
    const lower = query.toLowerCase();
    return extensions.filter(
      ext =>
        ext.name.toLowerCase().includes(lower) ||
        ext.description.toLowerCase().includes(lower) ||
        ext.author.toLowerCase().includes(lower),
    );
  }, [extensions, query]);

  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');

  return (
    <div className="settings-view__extensions">
      {filtered.length === 0 ? (
        <div className="form" style={{ padding: '32px', textAlign: 'center' }}>
          <span style={{ color: 'var(--text-400, rgba(229, 229, 234, 0.4))' }}>
            No extensions match your search
          </span>
        </div>
      ) : (
        <>
          {raycastExts.length > 0 && (
            <div className="settings-section">
              <div className="settings-section__title">Built-in</div>
              {raycastExts.map(ext => (
                <div
                  key={ext.id}
                  className="settings-extension"
                  onClick={() => onToggle(ext.id)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={e => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      onToggle(ext.id);
                    }
                  }}
                >
                  <div className="settings-extension__icon">{ext.icon()}</div>
                  <div className="settings-extension__info">
                    <div className="settings-extension__name">{ext.name}</div>
                    <div className="settings-extension__meta">
                      {ext.description}
                    </div>
                  </div>
                  <div className="settings-extension__toggle">
                    <ToggleSwitch
                      checked={ext.enabled}
                      onChange={() => onToggle(ext.id)}
                      label={`Toggle ${ext.name}`}
                    />
                  </div>
                </div>
              ))}
            </div>
          )}
          {communityExts.length > 0 && (
            <div className="settings-section">
              <div className="settings-section__title">Community</div>
              {communityExts.map(ext => (
                <div
                  key={ext.id}
                  className="settings-extension"
                  onClick={() => onToggle(ext.id)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={e => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      onToggle(ext.id);
                    }
                  }}
                >
                  <div className="settings-extension__icon">{ext.icon()}</div>
                  <div className="settings-extension__info">
                    <div className="settings-extension__name">{ext.name}</div>
                    <div className="settings-extension__meta">
                      {ext.description} &middot; {ext.author}
                    </div>
                  </div>
                  <div className="settings-extension__toggle">
                    <ToggleSwitch
                      checked={ext.enabled}
                      onChange={() => onToggle(ext.id)}
