    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut({ key: 'k', meta: true }, toggleActions);

  const dropdownSections: DropdownSection[] = useMemo(() => {
    const sections: DropdownSection[] = [
      {
        title: 'Navigation',
        actions: [
          {
            label: 'General',
            onClick: () => {
              setActiveTab('general');
              setActionsOpen(false);
            },
          },
          {
            label: 'Extensions',
            onClick: () => {
              setActiveTab('extensions');
              setActionsOpen(false);
            },
          },
          {
            label: 'Advanced',
            onClick: () => {
              setActiveTab('advanced');
              setActionsOpen(false);
            },
          },
        ],
      },
    ];

    if (activeTab === 'advanced') {
      sections.push({
        title: 'Actions',
        actions: [
          { label: 'Export Settings', onClick: handleExport },
          { label: 'Import Settings', onClick: handleImport },
          { label: 'Clear Cache', onClick: handleClearCache },
          { label: 'Reset All Settings', onClick: handleResetAll },
        ],
      });
    }

    return sections;
  }, [activeTab, handleExport, handleImport, handleClearCache, handleResetAll]);

  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder={
          activeTab === 'extensions'
            ? 'Search Extensions...'
            : 'Settings'
        }
        breadcrumbs={
          nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
        }
        dropdown={
          <SearchDropdown
            sections={TAB_SECTIONS}
            value={activeTab}
            onChange={handleTabChange}
          />
        }
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          <div className="settings-view">
            {activeTab === 'general' && (
              <GeneralTab
                settings={settings}
                onSettingsChange={setSettings}
              />
            )}
            {activeTab === 'extensions' && (
              <ExtensionsTab
                extensions={extensions}
                onToggle={handleToggleExtension}
                query={query}
              />
            )}
            {activeTab === 'advanced' && (
              <AdvancedTab
                onExport={handleExport}
                onImport={handleImport}
                onClearCache={handleClearCache}
                onResetAll={handleResetAll}
              />
            )}
          </div>
        </div>
      </div>
      <ActionPanel
        contextLabel="Settings"
        actions={[
          { label: 'Select', shortcut: <Kbd keys={['↵']} /> },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      {alertState && (
        <Alert
          title={alertState.title}
          message={alertState.message}
          icon={alertState.icon}
          primaryAction={alertState.primaryAction}
          dismissAction={alertState.dismissAction}
          onDismiss={dismissAlert}
        />
      )}
      <HUDContainer items={hudItems} />
    </>
  );
}

